  1	import * as React from 'react';
  2	import { IRow, ThProps } from '@patternfly/react-table';
  3	import { Button, ButtonVariant, FormSelect, FormSelectOption, TextInput } from '@patternfly/react-core';
  4	import { isValidIp } from '../../../../utils/IstioConfigUtils';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { PFColors } from '../../../../components/Pf/PfColors';
  7	import { isValid } from 'utils/Common';
  8	import { SimpleTable } from 'components/Table/SimpleTable';
  9	import { KialiIcon } from 'config/KialiIcon';
 10	import { t, useKialiTranslation } from 'utils/I18nUtils';
 11	
 12	type Props = {
 13	  onAddFrom: (source: { [key: string]: string[] }) => void;
 14	};
 15	
 16	const INIT_SOURCE_FIELDS = [
 17	  'principals',
 18	  'notPrincipals',
 19	  'requestPrincipals',
 20	  'notRequestPrincipals',
 21	  'namespaces',
 22	  'notNamespaces',
 23	  'ipBlocks',
 24	  'notIpBlocks'
 25	].sort();
 26	
 27	const noSourceStyle = kialiStyle({
 28	  color: PFColors.Red100
 29	});
 30	
 31	const columns: ThProps[] = [
 32	  {
 33	    title: t('Source Field'),
 34	    width: 20
 35	  },
 36	  {
 37	    title: t('Values'),
 38	    width: 80
 39	  },
 40	  {
 41	    title: ''
 42	  }
 43	];
 44	
 45	export const SourceBuilder: React.FC<Props> = (props: Props) => {
 46	  const [newSourceField, setNewSourceField] = React.useState<string>(INIT_SOURCE_FIELDS[0]);
 47	  const [newValues, setNewValues] = React.useState<string>('');
 48	  const [source, setSource] = React.useState<{ [key: string]: string[] }>({});
 49	  const [sourceFields, setSourceFields] = React.useState<string[]>(INIT_SOURCE_FIELDS);
 50	
 51	  const { t } = useKialiTranslation();
 52	
 53	  const onAddNewSourceField = (_event: React.FormEvent, value: string): void => {
 54	    setNewSourceField(value);
 55	  };
 56	
 57	  const onAddNewValues = (_event: React.FormEvent, value: string): void => {
 58	    setNewValues(value);
 59	  };
 60	
 61	  const onAddSource = (): void => {
 62	    const newSourceFields = [...sourceFields];
 63	    const i = sourceFields.indexOf(newSourceField);
 64	
 65	    if (i > -1) {
 66	      newSourceFields.splice(i, 1);
 67	    }
 68	
 69	    const newSource = { ...source };
 70	    newSource[newSourceField] = newValues.split(',');
 71	
 72	    setSource(newSource);
 73	    setSourceFields(newSourceFields);
 74	    setNewSourceField(newSourceFields[0]);
 75	    setNewValues('');
 76	  };
 77	
 78	  const onAddSourceFromList = (): void => {
 79	    const fromItem = source;
 80	
 81	    setSourceFields(INIT_SOURCE_FIELDS);
 82	    setSource({});
 83	    setNewSourceField(INIT_SOURCE_FIELDS[0]);
 84	    setNewValues('');
 85	
 86	    props.onAddFrom(fromItem);
 87	  };
 88	
 89	  // Helper to identify when some values are valid
 90	  const isValidSource = (): [boolean, string] => {
 91	    if (newSourceField === 'ipBlocks' || newSourceField === 'notIpBlocks') {
 92	      const validIp = newValues.split(',').every(ip => isValidIp(ip));
 93	
 94	      if (!validIp) {
 95	        return [false, t('Not valid IP')];
 96	      }
 97	    }
 98	
 99	    const emptyValues = newValues.split(',').every(v => v.length === 0);
100	
101	    if (emptyValues) {
102	      return [false, t('Empty value')];
103	    }
104	
105	    return [true, ''];
106	  };
107	
108	  const onRemoveSource = (removeSourceField: string): void => {
109	    let newSourceFields = [...sourceFields];
110	    newSourceFields.push(removeSourceField);
111	    newSourceFields = newSourceFields.sort();
112	
113	    const newSource = { ...source };
114	    delete newSource[removeSourceField];
115	
116	    setSource(newSource);
117	    setSourceFields(newSourceFields);
118	    setNewSourceField(newSourceFields[0]);
119	    setNewValues('');
120	  };
121	
122	  const rows = (): IRow[] => {
123	    const [validSource, invalidText] = isValidSource();
124	
125	    const sourceRows = Object.keys(source).map((sourceField, i) => {
126	      return {
127	        key: `sourceKey_${i}`,
128	        cells: [
129	          <>{sourceField}</>,
130	          <>{source[sourceField].join(',')}</>,
131	          <Button
132	            id="removeSourceBtn"
133	            variant={ButtonVariant.link}
134	            icon={<KialiIcon.Delete />}
135	            onClick={() => onRemoveSource(sourceField)}
136	          />
137	        ]
138	      };
139	    });
140	
141	    if (sourceFields.length > 0) {
142	      return sourceRows.concat([
143	        {
144	          key: 'sourceKeyNew',
145	          cells: [
146	            <FormSelect
147	              value={newSourceField}
148	              id="addNewSourceField"
149	              name="addNewSourceField"
150	              onChange={onAddNewSourceField}
151	            >
152	              {sourceFields.map((option, index) => (
153	                <FormSelectOption isDisabled={false} key={`source_${index}`} value={option} label={option} />
154	              ))}
155	            </FormSelect>,
156	            <>
157	              <TextInput
158	                value={newValues}
159	                type="text"
160	                id="addNewValues"
161	                key="addNewValues"
162	                aria-describedby={t('Add new source values')}
163	                name="addNewValues"
164	                onChange={onAddNewValues}
165	                validated={isValid(validSource)}
166	              />
167	
168	              {!validSource && (
169	                <div key="hostsHelperText" className={noSourceStyle}>
170	                  {invalidText}
171	                </div>
172	              )}
173	            </>,
174	            <>
175	              {sourceFields.length > 0 && (
176	                <Button
177	                  variant={ButtonVariant.link}
178	                  icon={<KialiIcon.AddMore />}
179	                  onClick={onAddSource}
180	                  isDisabled={!validSource}
181	                />
182	              )}
183	            </>
184	          ]
185	        }
186	      ]);
187	    }
188	
189	    return sourceRows;
190	  };
191	
192	  return (
193	    <>
194	      <SimpleTable label={t('Source Builder')} columns={columns} rows={rows()} />
195	
196	      <Button
197	        variant={ButtonVariant.link}
198	        icon={<KialiIcon.AddMore />}
199	        isDisabled={Object.keys(source).length === 0}
200	        onClick={onAddSourceFromList}
201	      >
202	        {t('Add Source to From List')}
203	      </Button>
204	    </>
205	  );
206	};

